/**
 * Data Service
 * Implementation for task T030
 * 
 * This service is responsible for:
 * - Loading data from JSON files
 * - Providing data to components
 * - Caching data in localStorage
 */

// Constants
const CACHE_VERSION = '1.0';
const CACHE_DURATION = 24 * 60 * 60 * 1000; // 24 hours in milliseconds
const CACHE_METADATA_KEY = 'portfolio_cache_metadata';

/**
 * Get cache key for a specific data type
 * @param {string} dataType - The type of data (e.g., 'profile', 'experience')
 * @returns {string} The cache key
 */
const getCacheKey = (dataType) => `portfolio_${dataType}_data`;

/**
 * Fetch data from a JSON file
 * @param {string} path - The path to the JSON file
 * @param {string} dataType - The type of data being fetched (for error messages)
 * @returns {Promise<any>} The parsed JSON data
 * @throws {Error} If the fetch fails or the response is not OK
 */
const fetchData = async (path, dataType) => {
  try {
    const response = await fetch(path);
    
    if (!response.ok) {
      const errorMessage = `Failed to load ${dataType} data: ${response.status} ${response.statusText}`;
      console.error(errorMessage);
      throw new Error(errorMessage);
    }
    
    return await response.json();
  } catch (error) {
    // If it's already our custom error with status code, rethrow it
    if (error.message.startsWith(`Failed to load ${dataType} data: `)) {
      throw error;
    }
    // Otherwise, wrap it in our custom error
    console.error(`Error fetching ${dataType} data:`, error);
    throw new Error(`Failed to load ${dataType} data`);
  }
};

/**
 * Save data to localStorage cache
 * @param {string} dataType - The type of data being cached
 * @param {any} data - The data to cache
 */
const saveToCache = (dataType, data) => {
  try {
    const cacheKey = getCacheKey(dataType);
    const cacheItem = {
      data,
      timestamp: Date.now()
    };
    
    localStorage.setItem(cacheKey, JSON.stringify(cacheItem));
    
    // Update cache metadata
    updateCacheMetadata();
  } catch (error) {
    console.warn(`Failed to cache ${dataType} data:`, error);
  }
};

/**
 * Get data from localStorage cache
 * @param {string} dataType - The type of data to retrieve
 * @returns {any|null} The cached data or null if not in cache or expired
 */
const getFromCache = (dataType) => {
  try {
    const cacheKey = getCacheKey(dataType);
    const cachedItem = localStorage.getItem(cacheKey);
    
    if (!cachedItem) return null;
    
    const parsedItem = JSON.parse(cachedItem);
    
    // Check if the cache is still valid
    if (Date.now() - parsedItem.timestamp > CACHE_DURATION) {
      // Cache is expired
      return null;
    }
    
    return parsedItem.data;
  } catch (error) {
    console.warn(`Failed to retrieve ${dataType} data from cache:`, error);
    return null;
  }
};

/**
 * Update cache metadata with the current timestamp and version
 */
const updateCacheMetadata = () => {
  try {
    const metadata = {
      timestamp: Date.now(),
      version: CACHE_VERSION
    };
    
    localStorage.setItem(CACHE_METADATA_KEY, JSON.stringify(metadata));
  } catch (error) {
    console.warn('Failed to update cache metadata:', error);
  }
};

/**
 * Get cache metadata
 * @returns {Object|null} The cache metadata or null if not available
 */
const getCacheMetadata = () => {
  try {
    const metadata = localStorage.getItem(CACHE_METADATA_KEY);
    
    if (!metadata) return null;
    
    return JSON.parse(metadata);
  } catch (error) {
    console.warn('Failed to get cache metadata:', error);
    return null;
  }
};

/**
 * Load data with caching
 * @param {string} path - The path to the JSON file
 * @param {string} dataType - The type of data being loaded
 * @returns {Promise<any>} The loaded data
 */
const loadDataWithCaching = async (path, dataType) => {
  // Try to get from cache first
  const cachedData = getFromCache(dataType);
  
  if (cachedData) {
    return cachedData;
  }
  
  // Not in cache or expired, fetch fresh data
  const data = await fetchData(path, dataType);
  
  // Save to cache for future use
  saveToCache(dataType, data);
  
  return data;
};

// DataService implementation
const DataService = {
  /**
   * Load profile data
   * @returns {Promise<Object>} Profile data
   */
  loadProfile: async () => {
    return await loadDataWithCaching('/data/profile.json', 'profile');
  },
  
  /**
   * Load experience data
   * @returns {Promise<Array>} Experience data
   */
  loadExperience: async () => {
    return await loadDataWithCaching('/data/experience.json', 'experience');
  },
  
  /**
   * Load projects data
   * @returns {Promise<Array>} Projects data
   */
  loadProjects: async () => {
    return await loadDataWithCaching('/data/projects.json', 'projects');
  },
  
  /**
   * Load skills data
   * @returns {Promise<Object>} Skills data
   */
  loadSkills: async () => {
    return await loadDataWithCaching('/data/skills.json', 'skills');
  },
  
  /**
   * Load education data
   * @returns {Promise<Array>} Education data
   */
  loadEducation: async () => {
    return await loadDataWithCaching('/data/education.json', 'education');
  },
  
  /**
   * Load awards data
   * @returns {Promise<Array>} Awards data
   */
  loadAwards: async () => {
    return await loadDataWithCaching('/data/awards.json', 'awards');
  },
  
  /**
   * Load languages data
   * @returns {Promise<Array>} Languages data
   */
  loadLanguages: async () => {
    return await loadDataWithCaching('/data/languages.json', 'languages');
  },
  
  /**
   * Load contact form data
   * @returns {Promise<Object>} Contact form data
   */
  loadContactForm: async () => {
    return await loadDataWithCaching('/data/contact-form.json', 'contactForm');
  },
  
  /**
   * Load all data at once
   * @returns {Promise<Object>} Complete portfolio data
   */
  loadAll: async () => {
    const [
      profile,
      experience,
      projects,
      skills,
      education,
      awards,
      languages,
      contactForm
    ] = await Promise.all([
      DataService.loadProfile(),
      DataService.loadExperience(),
      DataService.loadProjects(),
      DataService.loadSkills(),
      DataService.loadEducation(),
      DataService.loadAwards(),
      DataService.loadLanguages(),
      DataService.loadContactForm()
    ]);
    
    return {
      profile,
      experience,
      projects,
      skills,
      education,
      awards,
      languages,
      contactForm
    };
  },
  
  /**
   * Clear all cached data
   */
  clearCache: () => {
    try {
      localStorage.clear();
    } catch (error) {
      console.error('Failed to clear cache:', error);
    }
  },
  
  /**
   * Check if the cache is valid
   * @returns {boolean} True if the cache is valid, false otherwise
   */
  isCacheValid: () => {
    const metadata = getCacheMetadata();
    
    if (!metadata) return false;
    
    // Check if the cache version is current
    if (metadata.version !== CACHE_VERSION) return false;
    
    // Check if the cache is still within the duration limit
    return (Date.now() - metadata.timestamp <= CACHE_DURATION);
  },
  
  /**
   * Get the age of the cache in seconds
   * @returns {number} The age of the cache in seconds, or 0 if no cache
   */
  getCacheAge: () => {
    const metadata = getCacheMetadata();
    
    if (!metadata) return 0;
    
    return Math.floor((Date.now() - metadata.timestamp) / 1000);
  }
};

export default DataService;
